import React from 'react';
import { motion as Motion } from 'framer-motion';
import { TrendingUp, TrendingDown, Minus, Activity } from 'lucide-react';

const ClientCard = ({ client, delay = 0, onClick }) => {
    const { id, name, loss, dataSize, status, prediction, actual, signal, confidence } = client;

    // Signal UI mapping matching the nexus_site.html table design
    const getSignalUI = (sig) => {
        switch (sig) {
            case 'BUY': return <span className="sig-tag sig-tag-buy">Buy</span>;
            case 'SELL': return <span className="sig-tag sig-tag-sell">Sell</span>;
            default: return <span className="sig-tag sig-tag-hold">Hold</span>;
        }
    };

    const getSignalColor = (sig) => {
        switch (sig) {
            case 'BUY': return 'text-accent2';
            case 'SELL': return 'text-danger';
            default: return 'text-[#6b5c28]';
        }
    };

    return (
        <Motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay }}
            onClick={onClick}
            className="group relative p-8 border-b border-r border-rule bg-white hover:bg-cream2 transition-colors duration-300 cursor-none interactive min-h-[280px] flex flex-col"
        >
            {/* Hover Line Top */}
            <div className="absolute top-0 left-0 right-0 h-[3px] scale-x-0 origin-left transition-transform duration-400 ease-out group-hover:scale-x-100 bg-ink"></div>

            {/* Header */}
            <div className="flex justify-between items-start mb-12">
                <div>
                    <div className="text-[10px] tracking-[0.2em] text-light mb-2">0{id}</div>
                    <h3 className="font-serif text-3xl text-ink tracking-tight mb-1">{name}</h3>
                    <div className="text-[10px] tracking-[0.1em] uppercase text-mid">{dataSize} Samples · Series Shard</div>
                </div>
                <div>
                    {getSignalUI(signal)}
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-x-4 gap-y-6 mt-auto">
                <div>
                    <div className="text-[10px] tracking-[0.1em] uppercase text-mid mb-1">Local Loss</div>
                    <div className="font-serif text-2xl text-ink">{loss.toFixed(4)}</div>
                </div>

                <div className="text-right">
                    <div className="text-[10px] tracking-[0.1em] uppercase text-mid mb-1">Target</div>
                    <div className="font-serif text-2xl text-ink">${actual.toFixed(2)}</div>
                </div>

                <div className="col-span-2 pt-4 border-t border-rule flex justify-between items-baseline">
                    <div className="text-xs text-mid">Forecast:</div>
                    <div className="flex items-center gap-3">
                        <span className={`font-serif text-xl ${getSignalColor(signal)}`}>${prediction.toFixed(2)}</span>
                        <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-[0.1em] text-mid">
                            <div className="w-8 h-0.5 bg-rule overflow-hidden">
                                <Motion.div
                                    initial={{ width: 0 }}
                                    animate={{ width: `${confidence}%` }}
                                    transition={{ duration: 1 }}
                                    className="h-full bg-ink"
                                />
                            </div>
                            {confidence.toFixed(0)}%
                        </div>
                    </div>
                </div>
            </div>
        </Motion.div>
    );
};

export default ClientCard;

import React, { useMemo } from 'react';
import { motion as Motion } from 'framer-motion';
import { Play, Pause, Server, Activity, ArrowRight, Share2, CheckCircle2, RotateCcw } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import EditorialCard from '../ui/EditorialCard';

const ServerPanel = ({ gameState, onRunRound, onToggleAuto }) => {
    const { globalLoss, isTraining, history } = gameState;

    // Prepare chart data
    const chartData = useMemo(() => {
        if (history.length === 0) return [];
        return history.map(h => ({
            round: h.round,
            loss: h.loss,
            accuracy: h.accuracy * 100
        }));
    }, [history]);

    return (
        <EditorialCard className="h-full flex flex-col pt-8">
            {/* Header */}
            <div className="px-8 pb-6 border-b border-rule flex items-end justify-between">
                <div>
                    <div className="section-label mb-4">Aggregation Server</div>
                    <h2 className="font-serif text-3xl text-ink">Global <em>Weights</em></h2>
                </div>
                <div className="flex gap-4">
                    <button
                        onClick={onToggleAuto}
                        className="nav-cta flex items-center gap-2"
                    >
                        {isTraining ? <Pause size={14} /> : <Play size={14} />}
                        {isTraining ? 'Pause' : 'Auto'}
                    </button>
                    <button
                        onClick={onRunRound}
                        disabled={isTraining}
                        className={`nav-cta flex items-center gap-2 ${isTraining ? 'opacity-50 cursor-not-allowed' : ''
                            }`}
                    >
                        <ArrowRight size={14} /> Step
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto">
                {/* Timeline Log */}
                <div className="p-8 border-b border-rule">
                    <div className="section-label mb-6">Execution Log</div>
                    <div className="space-y-4">
                        {history.slice(-3).reverse().map((h, _idx) => (
                            <Motion.div
                                key={h.round}
                                initial={{ opacity: 0, x: -10 }}
                                animate={{ opacity: 1, x: 0 }}
                                className="grid grid-cols-[auto_1fr_auto] gap-6 items-center text-sm"
                            >
                                <div className="font-serif italic text-light w-16">Rnd {h.round}</div>
                                <div className="text-mid">
                                    FedAvg aggregation complete. Loss reduced to <span className="text-ink font-medium">{h.loss.toFixed(4)}</span>
                                </div>
                                <div className="flex items-center text-[10px] uppercase tracking-[0.1em] text-accent2">
                                    <CheckCircle2 size={12} className="mr-2" />
                                    Success
                                </div>
                            </Motion.div>
                        ))}
                        {history.length === 0 && (
                            <div className="text-mid text-sm italic">Waiting for initial round...</div>
                        )}
                    </div>
                </div>

                {/* Charts Grid */}
                <div className="p-8 grid grid-rows-2 h-[400px] gap-8">
                    {/* Loss Chart */}
                    <div className="flex flex-col">
                        <div className="flex items-center justify-between mb-4">
                            <span className="text-[10px] uppercase tracking-[0.1em] text-mid">Global Loss Convergence</span>
                            <span className="font-serif text-accent2 text-xl">{globalLoss.toFixed(4)}</span>
                        </div>
                        <div className="flex-1 min-h-0">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={chartData}>
                                    <defs>
                                        <linearGradient id="lossGradient" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="var(--color-ink)" stopOpacity={0.15} />
                                            <stop offset="95%" stopColor="var(--color-ink)" stopOpacity={0} />
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                    <XAxis dataKey="round" tickLine={false} axisLine={false} tickMargin={8} />
                                    <YAxis domain={['auto', 'auto']} tickLine={false} axisLine={false} tickMargin={8} width={40} />
                                    <Tooltip
                                        contentStyle={{ border: 'none' }}
                                        itemStyle={{ color: 'var(--color-cream)' }}
                                    />
                                    <Area
                                        type="monotone"
                                        dataKey="loss"
                                        stroke="var(--color-ink)"
                                        strokeWidth={2}
                                        fill="url(#lossGradient)"
                                        isAnimationActive={false}
                                    />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Protocol Info */}
                    <div className="flex flex-col border-t border-rule pt-8">
                        <div className="section-label mb-6">Algorithm Detail</div>
                        <div className="bg-cream2 p-6 rounded-sm border border-rule">
                            <div className="flex items-center gap-4 mb-4">
                                <Share2 className="text-accent2" size={20} />
                                <h3 className="font-serif text-xl tracking-tight text-ink">Federated Averaging</h3>
                            </div>
                            <div className="font-serif italic text-lg text-mid mb-4">
                                w_global ← Σ(n_k / N) · w_k
                            </div>
                            <p className="text-sm text-mid leading-relaxed">
                                The aggregation server waits for all 5 simulated clients to complete local epochs using their private stock shards. Gradients are collected, volume-weighted, and applied to the central model.
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </EditorialCard>
    );
};

export default ServerPanel;
